// Description: Collects per-repository online status and proxy auto-block state.
// Description: Fetches the repo list for online status; for proxy repos, fetches detailed config for block state.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("nexus.host")
def user = hostProps.get("nexus.user")
def pass = hostProps.get("nexus.pass")
def port = hostProps.get("nexus.port") ?: "8081"
def useSsl = (hostProps.get("nexus.ssl") ?: "true").toLowerCase() == "true"
def repoName = instanceProps.get("wildvalue")
def repoFormat = instanceProps.get("auto.repo.format")
def repoType = instanceProps.get("auto.repo.type")

def results = [
    "online": 0,
    "proxy_blocked": 0
]

if (!host || !user || !pass || !repoName) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def credentials = "${user}:${pass}".bytes.encodeBase64().toString()

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def nexusGet(String path, String baseUrl, String credentials) {
    try {
        def url = new URL("${baseUrl}${path}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Basic ${credentials}")
        conn.setRequestProperty("Accept", "application/json")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)
        if (conn.responseCode == 200) {
            return new JsonSlurper().parseText(conn.inputStream.text)
        } else {
            System.err.println("Nexus API error: HTTP ${conn.responseCode} for ${path}")
        }
    } catch (Exception e) {
        System.err.println("Nexus API error for ${path}: ${e.message}")
    }
    return null
}

// Fetch repo list and find this instance for online status
def repos = nexusGet("/service/rest/v1/repositories", baseUrl, credentials)
if (repos != null) {
    def repo = repos.find { it.name == repoName }
    if (repo) {
        results["online"] = (repo.online != false) ? 1 : 0
    }
}

// For proxy repos, check auto-block status via the format-specific detail endpoint
if (repoType == "proxy" && repoFormat) {
    def encodedName = java.net.URLEncoder.encode(repoName, "UTF-8")
    def detail = nexusGet("/service/rest/v1/repositories/${repoFormat}/proxy/${encodedName}", baseUrl, credentials)
    if (detail) {
        def httpClient = detail.httpClient
        if (httpClient?.connection) {
            def blocked = httpClient.connection.blocked ?: false
            def autoBlocked = httpClient.connection.autoBlock ?: false
            results["proxy_blocked"] = (blocked || (autoBlocked && detail.proxy?.remoteUrl == null)) ? 1 : 0
        }
        // Also check if the proxy status indicates auto-blocking via nested status field
        if (detail.status) {
            def proxyMode = detail.status.proxyMode ?: ""
            if (proxyMode.toLowerCase().contains("blocked")) {
                results["proxy_blocked"] = 1
            }
        }
    }
}

results.each { k, v -> println("${k}:${v}") }
return 0
